const item = $input.first();
const body = item.json.body || item.json;

// Check if this is audio upload (binary) or text transcript
const hasBinary = item.binary && Object.keys(item.binary).length > 0;
const hasTextTranscript = body.transcript || body.text;

return [{
  json: {
    meetingTitle: body.title || body.meetingTitle || 'Meeting Notes',
    meetingDate: body.date || new Date().toISOString().split('T')[0],
    attendees: body.attendees || body.participants || '',
    project: body.project || '',
    submittedBy: body.submittedBy || body.email || '',
    inputType: hasBinary ? 'audio' : 'text',
    textTranscript: hasTextTranscript ? (body.transcript || body.text) : null
  },
  binary: item.binary || {}
}];

const parsed = $('Code - Parse Input Type').first().json;
const whisperResult = $input.first().json;

const transcript = whisperResult.text || parsed.textTranscript || 'No transcript available';
const duration = whisperResult.duration ? `${Math.round(whisperResult.duration / 60)} minutes` : 'Unknown';

return [{
  json: {
    ...parsed,
    transcript,
    duration
  }
}];

