parameters.jsCode:
const meetingData = $('Code - Merge Transcript').first().json;
const aiRaw = $input.first().json.message?.content || '{}';

let analysis;
try { analysis = JSON.parse(aiRaw); }
catch (e) { analysis = { summary: aiRaw, key_decisions: [], action_items: [], blockers: [], topics_discussed: [], next_meeting: 'Not scheduled' }; }

// Build Notion page blocks
const actionItemsBlocks = (analysis.action_items || []).map(item =>
  `☐ **${item.task}** — Owner: ${item.owner} | Due: ${item.due_date} | Priority: ${item.priority}`
).join('\n');

const decisionsText = (analysis.key_decisions || []).map(d => `• ${d}`).join('\n');
const blockersText = (analysis.blockers || []).map(b => `⚠️ ${b}`).join('\n');
const topicsText = (analysis.topics_discussed || []).map(t => `• ${t}`).join('\n');

return [{
  json: {
    ...meetingData,
    analysis,
    actionItemsBlocks,
    decisionsText,
    blockersText,
    topicsText,
    pageTitle: `${meetingData.meetingDate} — ${meetingData.meetingTitle}`
  }
}];

